const r0 = mermaid.parseMermaid(source)
if (!r0.ok) return { phase: 'parse', errors: r0.error }
const seq = mermaid.asSequence(r0.value)
const verify = mermaid.verifyMermaid(r0.value)
const verifyOk = verify.ok
const warnings = verify.warnings
if (!verifyOk) return { phase: 'verify', warnings }
